import React, { useEffect, useRef } from "react";
import colorWheel from "../assets/images/colorwheel.jpeg";

const ColorPicker = ({ onColorChange }) => {
  const canvasRef = useRef(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    const ctx = canvas.getContext("2d");
    const image = new Image();
    image.src = colorWheel;
    image.onload = () => {
      ctx.drawImage(image, 0, 0, canvas.width, canvas.height);

      console.log("Color wheel image loaded and drawn on canvas.");

    };

    image.onerror = () => {
      console.error("Failed to load the color wheel image.");
    };
  }, []);

  const handleCanvasClick = (event) => {
    const canvas = canvasRef.current;
    const ctx = canvas.getContext("2d");
    const rect = canvas.getBoundingClientRect();
    const x = event.clientX - rect.left;
    const y = event.clientY - rect.top;
    const pixel = ctx.getImageData(x, y, 1, 1).data;
    const [r, g, b] = pixel;
    const hexColor = `#${((1 << 24) + (r << 16) + (g << 8) + b)
      .toString(16)
      .slice(1)}`;

    console.log("Selected Color (HEX):", hexColor);
    onColorChange(hexColor);
  };

  return (
    <canvas
      ref={canvasRef}
      width={694}
      height={439}
      className="color-picker"
      onClick={handleCanvasClick}
    />
  );
};

export default ColorPicker;
